import React, { useState } from "react";

export default function CompleteRegister({ email, closeModal }) {
  const BASE_URL = "http://localhost:8086";

  const [form, setForm] = useState({
    username: "",
    name: "",
    password: "",
    confirmPassword: "",
  });

  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const register = async () => {
    if (form.password !== form.confirmPassword) {
      setError("Passwords do not match");
      return;
    }

    try {
      const res = await fetch(`${BASE_URL}/user/register-final`, {
        method: "POST",
        headers: {"Content-Type": "application/json"},
        body: JSON.stringify({
          ...form,
          email,
        }),
      });

      const data = await res.text();

      if (res.ok) {
        setSuccess("Registered successfully 🎉");
        setTimeout(() => closeModal(), 1200);
      } else {
        setError(data);
      }
    } catch {
      setError("Server error");
    }
  };

  return (
    <div className="p-8 bg-white/20 rounded-xl text-white">
      <h2 className="text-xl mb-4">Complete Registration</h2>

      <input name="username" onChange={handleChange} placeholder="Username" className="w-full p-2 mb-2 text-black" />
      <input name="name" onChange={handleChange} placeholder="Full Name" className="w-full p-2 mb-2 text-black" />
      <input type="password" name="password" onChange={handleChange} placeholder="Password" className="w-full p-2 mb-2 text-black" />
      <input type="password" name="confirmPassword" onChange={handleChange} placeholder="Confirm Password" className="w-full p-2 mb-2 text-black" />

      {error && <p className="text-red-300">{error}</p>}
      {success && <p className="text-green-300">{success}</p>}

      <button onClick={register} className="bg-blue-500 px-4 py-2 mt-3">
        Register
      </button>
    </div>
  );
}
